SELECT character_id
FROM character_items
WHERE character_item_id = 0;

SELECT item_name, item_type, rarity
FROM item_loot
WHERE rarity = 'Rare';

SELECT SUM(item_value) AS total_epic_item_value
FROM item_loot
WHERE rarity = 'Epic';

SELECT COUNT(skill_id) 
FROM character_skills 
WHERE character_id = (SELECT character_id FROM characters WHERE character_name = 'Thief');

SELECT skill_points
FROM character_skills
WHERE character_id = (SELECT character_id FROM characters WHERE character_name = 'Alice');

SELECT COUNT(DISTINCT cq.character_id) AS unique_characters_completed_quests
  FROM character_quests cq
  WHERE cq.completion_status = 'Completed';

SELECT q.quest_name
FROM quests q
WHERE q.quest_level > (
  SELECT AVG(cs.skill_level)
  FROM character_skills cs
);
